    "durationSec": 3.9466666666666668,
    "durationFrames": 118,
    "speaker": "めたん",
    "text": "しかも、自分のリポジトリでやってるんでしょ？ 皔のアプリじゃないと。",
    "speakerColor": "#d6336c",
    "sceneId": 17,
    "sceneTitle": "METR研究の逆説",
