    "startFrame": 19861,
    "durationSec": 3.1573333333333333,
    "durationFrames": 95,
    "speaker": "ずんだもん",
    "text": "で、まず開発者たちの予想を聞いたのだ。",
    "speakerColor": "#22c55e",
    "sceneId": 17,
    "sceneTitle": "METR研究の逆説",
